#!/usr/bin/env node
const fs = require('fs');
const path = require('path');
const os = require('os');

const root = process.cwd();
const patchName = 'account-stability-dashboard-auth-fix';
const stamp = new Date().toISOString().replace(/[:.]/g, '-');
const backupRoot = path.join(os.tmpdir(), 'barndaksa-patch-backups', `${patchName}-${stamp}`);

const files = {
  "app/actions/customer-account.ts": "",
  "app/c/[slug]/account/page.tsx": "",
  "app/actions/dashboard-shell.ts": "",
  "lib/performance/dashboard-shell-client.ts": "",
  "components/dashboard/DashboardSidebar.tsx": "",
  "components/dashboard/dashboard-app-layout.tsx": "",
  "components/cafe/cafe-logo.tsx": ""
};

function ensureDir(filePath) {
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
}

function backup(relativePath) {
  const target = path.join(root, relativePath);
  if (!fs.existsSync(target)) return;
  const backupPath = path.join(backupRoot, relativePath);
  ensureDir(backupPath);
  fs.copyFileSync(target, backupPath);
}

function write(relativePath, b64) {
  const target = path.join(root, relativePath);
  ensureDir(target);
  backup(relativePath);
  fs.writeFileSync(target, Buffer.from(b64, 'base64'));
  console.log('updated', relativePath);
}

for (const [relativePath, b64] of Object.entries(files)) {
  write(relativePath, b64);
}

console.log('');
console.log('✅ تم تطبيق إصلاح ثبات حساب العميل ولوحة العلامة.');
console.log('نسخة احتياطية خارج المشروع: ' + backupRoot);
console.log('شغل الآن: npm exec tsc -- --noEmit ثم npm run build');
